children.text:
@font-face {
    font-family: 'Ahem';
    src: url('file:///Users/henryluo/Projects/Jubily/test/layout/data/wpt-css-text/support/ahem3.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
}

.justified {
    font: 10px/1 Ahem;
    text-align: justify;
    text-justify: inter-word;
    width: 120px;
    border: solid 1px black;
}
/* Hide the word separators, in case the system doesn't
   have an appropriate font installed and shows tofu.
   Justification should still work in this case. */
.hidden {
    color: transparent;
}
